files.content:
@use 'variables/colors' as *;

// ==========================================
// 全局基础样式
// ==========================================

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-family: $font-sans;
  font-size: 16px;
  line-height: $leading-normal;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

body {
  background-color: $background;
  color: $foreground;
  font-family: $font-sans;
  font-size: $text-base;
  line-height: $leading-normal;
}

// ==========================================
// 链接样式
// ==========================================

a {
  color: $primary;
  text-decoration: none;

  &:hover {
    text-decoration: underline;
  }
}

// ==========================================
// 按钮重置
// ==========================================

button,
[type="button"],
[type="reset"],
[type="submit"] {
  -webkit-appearance: button;
  background: transparent;
  border: none;
  cursor: pointer;
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
  padding: 0;
}

// ==========================================
// 输入框重置
// ==========================================

input,
textarea,
select {
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
}

// ==========================================
// 图片重置
// ==========================================

img {
  display: block;
  max-width: 100%;
}

// ==========================================
// 标题样式
// ==========================================

h1, h2, h3, h4, h5, h6 {
  font-weight: $font-semibold;
  line-height: $leading-tight;
}

h1 { font-size: $text-3xl; }
h2 { font-size: $text-2xl; }
h3 { font-size: $text-xl; }
h4 { font-size: $text-lg; }
h5 { font-size: $text-base; }
h6 { font-size: $text-sm; }

// ==========================================
// 工具类
// ==========================================

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.container {
  width: 100%;
  margin-left: auto;
  margin-right: auto;
  padding-left: $spacing-4;
  padding-right: $spacing-4;

  @media (min-width: 640px) {
    max-width: 640px;
  }

  @media (min-width: 768px) {
    max-width: 768px;
  }

  @media (min-width: 1024px) {
    max-width: 1024px;
  }

  @media (min-width: 1280px) {
    max-width: 1280px;
  }
}

// ==========================================
// 基础颜色变量
// ==========================================

// 主色调
$primary: #18181b;
$primary-foreground: #fafafa;

// 辅助色
$secondary: #f4f4f5;
$secondary-foreground: #18181b;

// 强调色
$accent: #f4f4f5;
$accent-foreground: #18181b;

// 破坏性操作颜色
$destructive: #ef4444;
$destructive-foreground: #fafafa;

// 成功颜色
$success: #22c55e;
$success-foreground: #fafafa;

// 警告颜色
$warning: #f59e0b;
$warning-foreground: #fafafa;

// 信息颜色
$info: #3b82f6;
$info-foreground: #fafafa;

// 背景色
$background: #ffffff;
$foreground: #18181b;

// 边框色
$border: #e4e4e7;
$input: #e4e4e7;
$ring: #18181b;

// 阴影
$shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
$shadow: 0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1);
$shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
$shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);

// 圆角
$radius-sm: 0.25rem;
$radius: 0.5rem;
$radius-md: 0.75rem;
$radius-lg: 1rem;
$radius-full: 9999px;

// 字体
$font-sans: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
$font-mono: ui-monospace, SFMono-Regular, 'SF Mono', Menlo, Consolas, 'Liberation Mono', monospace;

// 字号
$text-xs: 0.75rem;
$text-sm: 0.875rem;
$text-base: 1rem;
$text-lg: 1.125rem;
$text-xl: 1.25rem;
$text-2xl: 1.5rem;
$text-3xl: 1.875rem;

// 字重
$font-light: 300;
$font-normal: 400;
$font-medium: 500;
$font-semibold: 600;
$font-bold: 700;

// 行高
$leading-none: 1;
$leading-tight: 1.25;
$leading-normal: 1.5;
$leading-relaxed: 1.625;

// 间距
$spacing-1: 0.25rem;
$spacing-2: 0.5rem;
$spacing-3: 0.75rem;
$spacing-4: 1rem;
$spacing-5: 1.25rem;
$spacing-6: 1.5rem;
$spacing-8: 2rem;
$spacing-10: 2.5rem;
$spacing-12: 3rem;

// 过渡
$transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
$transition-normal: 200ms cubic-bezier(0.4, 0, 0.2, 1);
$transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);

// 层级
$z-dropdown: 1000;
$z-modal: 1050;
$z-popover: 1060;
$z-tooltip: 1070;

// ==========================================
// 基础混入工具
// ==========================================

// 清除浮动
@mixin clearfix {
  &::after {
    content: '';
    display: table;
    clear: both;
  }
}

// 隐藏文本
@mixin hide-text {
  overflow: hidden;
  text-indent: -9999px;
}

// 绝对定位居中
@mixin center-absolutely {
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
}

// Flex 居中
@mixin flex-center {
  display: flex;
  align-items: center;
  justify-content: center;
}

// Flex 垂直居中
@mixin flex-center-vertical {
  display: flex;
  align-items: center;
}

// Flex 水平居中
@mixin flex-center-horizontal {
  display: flex;
  justify-content: center;
}

// 省略号
@mixin ellipsis($lines: 1) {
  @if $lines == 1 {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  } @else {
    display: -webkit-box;
    overflow: hidden;
    text-overflow: ellipsis;
    -webkit-line-clamp: $lines;
    -webkit-box-orient: vertical;
  }
}

// 响应式断点
$breakpoints: (
  'sm': 640px,
  'md': 768px,
  'lg': 1024px,
  'xl': 1280px,
  '2xl': 1536px
);

@mixin respond-to($breakpoint) {
  @if map-has-key($breakpoints, $breakpoint) {
    @media (min-width: map-get($breakpoints, $breakpoint)) {
      @content;
    }
  } @else {
    @media (min-width: $breakpoint) {
      @content;
    }
  }
}

// 主题变量生成
@mixin theme-variables($theme-prefix: 'tile') {
  #{$theme-prefix}-primary: #{$primary};
  #{$theme-prefix}-primary-foreground: #{$primary-foreground};
  #{$theme-prefix}-secondary: #{$secondary};
  #{$theme-prefix}-secondary-foreground: #{$secondary-foreground};
  #{$theme-prefix}-accent: #{$accent};
  #{$theme-prefix}-accent-foreground: #{$accent-foreground};
  #{$theme-prefix}-destructive: #{$destructive};
  #{$theme-prefix}-destructive-foreground: #{$destructive-foreground};
  #{$theme-prefix}-background: #{$background};
  #{$theme-prefix}-foreground: #{$foreground};
  #{$theme-prefix}-border: #{$border};
  #{$theme-prefix}-input: #{$input};
  #{$theme-prefix}-ring: #{$ring};
}

// 焦点状态
@mixin focus-ring {
  &:focus-visible {
    outline: none;
    box-shadow: 0 0 0 2px $background, 0 0 0 4px $ring;
  }
}

// 禁用状态
@mixin disabled {
  &:disabled,
  &.disabled,
  &[disabled] {
    pointer-events: none;
    opacity: 0.5;
    cursor: not-allowed;
  }
}
